import{_ as t,a}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as n,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Safety/webdav-site-access.md","filePath":"vi-VN/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),d={name:"vi-VN/Safety/webdav-site-access.md"};function s(r,e,c,h,p,g){return n(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>WebDAV setting trong Security Settings đưa ImgBed site của bạn thành một WebDAV endpoint.</p><p>Sau khi bật, bạn có thể dùng Windows, macOS, mobile file managers hoặc bất kỳ WebDAV-compatible client nào để browse, upload, delete và manage ImgBed files như một remote folder.</p><p>Đây là WebDAV access entry của site. Nó khác với WebDAV storage channel trong Upload Settings. Upload channel lưu files vào third-party WebDAV service. Setting này cho phép ImgBed site cung cấp WebDAV access cho clients.</p><h2 id="cau-hinh-o-đau" tabindex="-1">Cấu hình ở đâu <a class="header-anchor" href="#cau-hinh-o-đau" aria-label="Permalink to &quot;Cấu hình ở đâu&quot;">​</a></h2><p>Mở admin panel, rồi vào:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Available settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="feature-nay-lam-gi" tabindex="-1">Feature này làm gì <a class="header-anchor" href="#feature-nay-lam-gi" aria-label="Permalink to &quot;Feature này làm gì&quot;">​</a></h2><p>Sau khi WebDAV được bật, ImgBed cung cấp fixed access URL:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>Dùng URL này để connect tới ImgBed file directory.</p><p>Các use cases phù hợp:</p><ul><li>Browse ImgBed files trực tiếp từ file manager trên máy tính.</li><li>Kéo images vào WebDAV folder để upload.</li><li>Organize ImgBed folders từ local file manager.</li><li>Dùng WebDAV-compatible software để sync hoặc manage images.</li><li>Access ImgBed content mà không cần mở admin panel.</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>Bật WebDAV endpoint.</p><p>Khi disabled, clients không thể connect qua WebDAV.</p><h3 id="username-va-password" tabindex="-1">Username và Password <a class="header-anchor" href="#username-va-password" aria-label="Permalink to &quot;Username và Password&quot;">​</a></h3><p>WebDAV clients dùng credentials này khi connect.</p><p>Hãy dùng WebDAV username và password riêng. Không dùng lại admin password hoặc upload password.</p><p>Nếu username hoặc password trống, WebDAV clients sẽ không connect đúng cách.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode quyết định WebDAV clients ưu tiên image URL nào khi đọc images.</p><p>Common choices:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed chọn theo context. Recommended cho normal use.</td></tr><tr><td>Original</td><td>Ưu tiên original images.</td></tr><tr><td>Thumbnail</td><td>Ưu tiên thumbnails. Hữu ích cho fast preview.</td></tr></tbody></table><p>Nếu chưa chắc, giữ <code>Smart loading</code>.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Default channel được dùng cho WebDAV uploads.</p><p>Khi bạn copy files vào WebDAV directory từ Windows hoặc client khác, ImgBed upload chúng qua selected default upload channel.</p><p>Nếu không chọn default channel, browsing có thể hoạt động, nhưng uploads có thể fail.</p><h2 id="access-webdav-trong-windows-11" tabindex="-1">Access WebDAV trong Windows 11 <a class="header-anchor" href="#access-webdav-trong-windows-11" aria-label="Permalink to &quot;Access WebDAV trong Windows 11&quot;">​</a></h2><p>Windows 11 có thể thêm WebDAV như một network location.</p><ol><li>Mở <code>This PC</code>.</li><li>Chọn <code>Add a network location</code>.</li><li>Nhập <code>https://your-domain.com/dav</code>.</li><li>Khi được hỏi, nhập WebDAV username và password.</li><li>Hoàn tất wizard. Sau đó có thể mở WebDAV directory trong File Explorer.</li></ol><p><img src="'+t+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>Sau khi thêm, WebDAV directory xuất hiện trong Windows File Explorer. Bạn có thể open, copy và manage files như folder bình thường.</p><p><img src="'+a+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>Sau khi WebDAV connection thành công, thường bạn có thể:</p><ul><li>View files và folders.</li><li>Upload files.</li><li>Create folders.</li><li>Rename files hoặc folders.</li><li>Move files.</li><li>Delete files.</li></ul><p>WebDAV phù hợp cho everyday access và small-scale file management. Với large moves, bulk deletes hoặc organization phức tạp, hãy dùng admin panel.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Successful WebDAV connections cũng xuất hiện trong WebDAV tab của Login Device Management.</p><p>Bạn có thể review WebDAV clients ở đó và force old devices offline khi cần.</p><p>Nếu đổi WebDAV username hoặc password, clients cũ cần sign in lại.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-lien-tuc-hoi-username-va-password" tabindex="-1">Windows liên tục hỏi Username và Password <a class="header-anchor" href="#windows-lien-tuc-hoi-username-va-password" aria-label="Permalink to &quot;Windows liên tục hỏi Username và Password&quot;">​</a></h3><p>Kiểm tra:</p><ul><li>URL là <code>https://your-domain.com/dav</code>.</li><li>Username và password khớp với WebDAV settings.</li><li>WebDAV đã enabled.</li><li>Site có thể access qua HTTPS.</li></ul><h3 id="browsing-hoat-đong-nhung-upload-fail" tabindex="-1">Browsing hoạt động, nhưng Upload fail <a class="header-anchor" href="#browsing-hoat-đong-nhung-upload-fail" aria-label="Permalink to &quot;Browsing hoạt động, nhưng Upload fail&quot;">​</a></h3><p>Kiểm tra <code>Default channel</code>.</p><p>WebDAV uploads cần default upload channel. Nếu thiếu, disabled hoặc misconfigured, uploads có thể fail.</p><h3 id="access-speed-khong-on-đinh" tabindex="-1">Access Speed không ổn định <a class="header-anchor" href="#access-speed-khong-on-đinh" aria-label="Permalink to &quot;Access Speed không ổn định&quot;">​</a></h3><p>WebDAV performance phụ thuộc vào client, network, file count và default upload channel.</p><p>Nếu một directory có nhiều files, hãy chia vào folders thay vì giữ quá nhiều files trong một directory.</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>Dùng HTTPS cho WebDAV access.</li><li>Đặt strong password.</li><li>Không share WebDAV password với người không trusted.</li><li>Tắt WebDAV khi không dùng.</li><li>Periodically clean up unused WebDAV devices trong Login Device Management.</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients không dùng large-file chunking flow của browser upload page. Với files vượt suggested limits bên dưới, hãy dùng web upload page.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(d,[["render",s]]);export{m as __pageData,f as default};
